from collections.abc import Awaitable, Callable


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]], max_concurrent: int
) -> None:
    """Run up to *max_concurrent* tasks at a time from the given list.

    Each item in *tasks* is a zero-argument async callable.  No more than
    *max_concurrent* tasks run concurrently.

    If the operation is cancelled (via ``asyncio.CancelledError``, e.g. by
    SIGINT through ``asyncio.run``) tasks that have already started are
    cancelled so their cleanup / ``finally`` blocks execute, while queued
    tasks that have not yet started are never started.
    """
    if max_concurrent <= 0:
        raise ValueError("max_concurrent must be positive")

    it = iter(tasks)
    running: set[asyncio.Task[None]] = set()

    # Start the initial batch — at most *max_concurrent* tasks.
    for _ in range(max_concurrent):
        try:
            fn = next(it)
        except StopIteration:
            break
        running.add(asyncio.create_task(fn()))

    try:
        # Process remaining tasks: whenever one finishes, start the next.
        while running:
            done, pending = await asyncio.wait(
                running, return_when=asyncio.FIRST_COMPLETED
            )
            running = pending

            for _ in done:
                try:
                    fn = next(it)
                except StopIteration:
                    continue
                running.add(asyncio.create_task(fn()))
    except asyncio.CancelledError:
        # Cancel tasks that have already started.  Their cleanup/finally
        # blocks will run.  Tasks still waiting in *it* are never started.
        for t in running:
            t.cancel()
        if running:
            await asyncio.wait(running)
        raise
